<script lang="ts">import { formatCurrency } from '$lib/utils/format'; let { data } = $props();</script>
<div class="mx-auto max-w-5xl px-6 py-10"><div class="no-print mb-6 flex justify-end gap-3"><button class="btn-secondary" data-testid="print-button" onclick={() => window.print()}>Print / Save PDF</button><a class="btn-primary" href={`/app/invoices/${data.invoice.id}`}>Back to editor</a></div><article class="card-elevated rounded p-10"><header data-testid="print-invoice-header" class="flex flex-wrap items-start justify-between gap-8 pb-8"><div><p class="label-md text-primary">Invoice</p><h1 class="display-md mt-4 text-on-surface">{data.invoice.invoiceNumber}</h1><p class="mt-3 body-sm text-on-surface-variant">Issue date: {data.invoice.issueDate}</p><p class="mt-1 body-sm text-on-surface-variant">Due date: {data.invoice.dueDate}</p></div><div class="max-w-sm text-right body-sm text-on-surface-variant"><h2 class="title-lg text-on-surface">{data.profile.companyName}</h2><p class="mt-2 whitespace-pre-line">{data.profile.companyAddress}</p><p class="mt-2">{data.profile.companyEmail}</p><p>{data.profile.companyPhone}</p></div></header><section class="grid gap-8 bg-surface-container-low py-8 px-6 rounded-sm mt-8 md:grid-cols-2"><div><p class="label-sm text-on-surface-variant">Bill to</p><h3 class="mt-3 title-lg text-on-surface">{data.invoice.customerName}</h3><p class="mt-2 whitespace-pre-line body-sm text-on-surface-variant">{data.invoice.customerAddress}</p><p class="mt-2 body-sm text-on-surface-variant">{data.invoice.customerEmail}</p></div><div class="md:text-right"><p class="label-sm text-on-surface-variant">Status</p><p class="mt-3 title-lg text-on-surface">{data.invoice.status}</p></div></section><section class="py-8"><table class="min-w-full text-left text-sm"><thead><tr class=" text-on-surface-variant"><th class="py-4 font-medium">Description</th><th class="py-4 text-right font-medium">Qty</th><th class="py-4 text-right font-medium">Rate</th><th class="py-4 text-right font-medium">Amount</th></tr></thead><tbody>{#each data.invoice.items as item}<tr class=" align-top"><td class="py-4 pr-6"><p class="font-medium text-on-surface">{item.name}</p><p class="mt-2 whitespace-pre-line text-on-surface-variant">{item.description}</p></td><td class="py-4 text-right text-on-surface-variant">{item.quantity}</td><td class="py-4 text-right text-on-surface-variant">{formatCurrency(item.unitPrice, data.invoice.currency)}</td><td class="py-4 text-right font-medium text-on-surface">{formatCurrency(item.lineTotal, data.invoice.currency)}</td></tr>{/each}</tbody></table></section><section class="grid gap-8 pt-8 md:grid-cols-[1fr_320px]"><div class="space-y-6 body-sm text-on-surface-variant"><div><p class="label-sm text-on-surface-variant">Notes</p><p class="mt-3 whitespace-pre-line">{data.invoice.notes || 'Thank you for your business.'}</p></div><div><p class="label-sm text-on-surface-variant">Payment instructions</p><p class="mt-3 whitespace-pre-line">{data.invoice.paymentInstructions}</p></div></div><div class="space-y-4 rounded-sm bg-surface-container-low p-6 body-md"><div class="flex justify-between"><span>Subtotal</span><span>{formatCurrency(data.invoice.subtotal, data.invoice.currency)}</span></div><div class="flex justify-between"><span>Discount</span><span>-{formatCurrency(data.invoice.discountAmount, data.invoice.currency)}</span></div><div class="flex justify-between"><span>Tax</span><span>{formatCurrency(data.invoice.taxAmount, data.invoice.currency)}</span></div><div data-testid="print-total-due" class="flex justify-between mt-4 pt-4 bg-surface-container px-6 -mx-6 py-4 text-base font-semibold text-on-surface"><span>Total due</span><span>{formatCurrency(data.invoice.totalAmount, data.invoice.currency)}</span></div></div></section></article></div>
